module mux4to1_1bit_active_high (
  input in0,
  input in1,
  input in2,
  input in3,
  input [2-1:1-1] sel,
  input en,
  output reg out
);

  always @(*) begin
    if (en) begin
      case (sel)
        2'b00: out = in0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 1'b0;
      endcase
    end else begin
      out = 1'b0;
    end
  end

endmodule
